#include <stdio.h>
int main() {
    int N, M, K, Q;
    scanf("%d %d %d", &N, &M, &K);
    int hazardous[N][M] = {0};
    for (int i = 0; i < K; i++) {
        int xi, yi;
        scanf("%d %d", &xi, &yi);
        hazardous[xi - 1][yi - 1] = 1;
    }
    int prefixSum[N][M] = {0};
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (i > 0) prefixSum[i][j] += prefixSum[i - 1][j];
            if (j > 0) prefixSum[i][j] += prefixSum[i][j - 1];
            if (i > 0 && j > 0) prefixSum[i][j] -= prefixSum[i - 1][j - 1];
            prefixSum[i][j] += hazardous[i][j];
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int Li, Hi;
        scanf("%d %d", &Li, &Hi);
        int maxArea = 0;
        for (int width = 1; width <= M; width++) {
            for (int j = 0; j <= M - width; j++) {
                int area = width * (Hi - Li + 1);
                int hazardousCells = 0;
                for (int k = Li - 1; k <= Hi - 1; k++) {
                    hazardousCells += prefixSum[k][j + width - 1];
                    if (j > 0) hazardousCells -= prefixSum[k][j - 1];
                }
                if (hazardousCells == 0) maxArea = (maxArea > area) ? maxArea : area;
            }
        }
        printf("%d\n", maxArea);
    }
    return 0;
}

